DELIMITER $$
CREATE TRIGGER `after_order_insert` AFTER INSERT ON `order_details` FOR EACH ROW BEGIN
        tracking_id,
        customer_id,
        product_id,
        product_name,
        vendor_id,
        placed_date,
        status ) 
VALUES (NEW.order_id,
      NEW.ids,
      NEW.customer_id,
      NEW.product_id,
      NEW.product_name,
      NEW.vendor_id,
      NEW.placed_date,
      NEW.status );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `after_order_status_update` AFTER UPDATE ON `order_details` FOR EACH ROW BEGIN
  IF NOT NEW.status <=> OLD.status THEN
      order_id,
      tracking_id,
      customer_id,
      product_id,
      product_name,
      vendor_id,
      placed_date,
      status
    )
    VALUES (
      NEW.order_id,
      NEW.ids,
      NEW.customer_id,
      NEW.product_id,
      NEW.product_name,
      NEW.vendor_id,
      NEW.placed_date,
      NEW.status
    );
  END IF;
END
$$
