--
-- Triggers `vendor_details`
--
DELIMITER $$
CREATE TRIGGER `after_vendor_details_insert` AFTER INSERT ON `vendor_details` FOR EACH ROW BEGIN
        vendor_id,
        email_username,
        user_password,
        phone_no,
        whatsapp_no,
        user_type,
        status,
        api_key,
        device_id,
        created_date
    ) VALUES (
        NEW.ids, -- vendor_id is the ids from vendor_details
        CONCAT(NEW.username, ',', NEW.gmail_id), -- Combine username and gmail_id
        NEW.password, -- Copy password
        '', -- Default empty for phone_no
        '', -- Default empty for whatsapp_no
        'vendor', -- Default user_type
        'Active', -- Default status
        '', -- Default empty for api_key
        '', -- Default empty for device_id
        CURRENT_TIMESTAMP -- Set created_date to current timestamp
    );
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `after_vendor_details_update` AFTER UPDATE ON `vendor_details` FOR EACH ROW BEGIN
    IF OLD.password != NEW.password THEN
        UPDATE `user_details`
        SET `user_password` = NEW.password
        WHERE `vendor_id` = NEW.ids;
    END IF;
END
$$
DELIMITER ;

