(160, 15, 6, 6, 'Blazer', 0, 'Default', 'Blazer Abaya', 'عباية بليزر', '', '', 38.00, 38.00, 0.00, 'Mix fabric Blazer abaya with stones', 'عباية بليزر من قماش مختلط مزينة بالأحجار', '', '', '', NULL, 0, 0, '2026-07-11 03:04:48', 'Active', NULL, '', 'yes', 29, NULL),
(162, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Lace and beaded abaya ✨', 'عباية من الدانتيل والخرز ✨', '', '', 40.00, 40.00, 0.00, 'An elegant design that combines the luxurious feel of lace with the shimmer of beads, featuring delicate details that add a touch of quiet femininity. This flowing abaya is perfect for sophisticated looks and special occasions, with exquisite side embroidery that gives it a distinctive and effortlessly elegant presence.', 'تصميم راقٍ يجمع بين فخامة الدانتيل ولمعة الخرز بتفاصيل ناعمة تضيف لمسة أنثوية هادئة. عباية بقصة انسيابية أنيقة مناسبة للإطلالات الراقية والمناسبات، مع تطريز جانبي فاخر يمنحها حضورًا مميزًا بكل بساطة.', '', '', '', NULL, 0, 0, '2026-07-11 22:41:15', 'Active', NULL, '', 'no', 6, NULL),
(163, 15, 6, 4, 'Black Abaya', 0, 'Default', 'elegant lace abaya', 'عباية دانتيل أنيقة', '', '', 35.00, 35.00, 0.00, 'A simple yet elegant black abaya with delicate lace details that adds a touch of understated sophistication. Its practical and flowing design makes it suitable for everyday looks and casual occasions with effortless style.', 'عباية سوداء بسيطة وأنيقة بتفاصيل دانتيل ناعمة تضيف لمسة راقية بدون مبالغة. تصميم عملي وانسيابي يناسب الإطلالات اليومية والمناسبات الخفيفة بكل أناقة', '', '', '', NULL, 0, 0, '2026-07-04 11:47:41', 'Active', NULL, '', 'no', 5, NULL),
(164, 15, 6, 4, 'Black Abaya', 0, 'Default', 'luxury of black', 'عباية فخامة الأسود', '', '', 40.00, 40.00, 0.00, 'An elegant abaya with soft pleats that adds distinctive movement and flow, adorned with refined lace details that reflect understated luxury and feminine taste, with a design that combines simplicity and luxurious classicism, suitable for occasions and elegant everyday looks.', 'عباية أنيقة بكسرات ناعمة تضيف حركة وانسيابية مميزة، مزينة بتفاصيل دانتيل راقية تعكس فخامة وذوق أنثوي هادئ، بتصميم يجمع بين البساطة والكلاسيك الفاخر، مناسبة للمناسبات والإطلالات اليومية الأنيقة', '', '', '', NULL, 0, 0, '2026-07-12 00:26:49', 'Active', NULL, '', 'no', 2, NULL),
(165, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Comfortable Abaya', 'عباية مريحة', '', '', 35.00, 35.00, 0.00, 'Combining a light texture and practical design, it\\\'s the perfect companion for every journey.', 'تجمع بين خفة الملمس وعملية التصميم.. لتكون رفيقتكِ المثالية في كل مشوار.', '', '', '', NULL, 0, 0, '2026-07-10 19:54:20', 'Active', NULL, '', 'no', 2, NULL),
(166, 15, 6, 10, 'Eid Collection', 0, 'Default', 'Abaya made of mixed fabric', 'عباية مصنوعة من قماش مختلط', '', '', 40.00, 40.00, 0.00, 'Simplicity of design meets luxurious fabric... for an unforgettable, elegant look.', 'بساطة التصميم تلتقي بـ فخامة القماش.. لتتألقي برقة لا تُنسى', '', '', '', NULL, 0, 0, '2026-06-04 11:53:06', 'Active', NULL, '', 'no', 1, NULL),
(167, 15, 6, 10, 'Eid Collection', 0, 'Default', 'Black Abaya', 'عباية سوداء', '', '', 38.00, 38.00, 0.00, 'A royal look... with everyday comfort', 'طلّة ملكية.. براحة يومية', '', '', '', NULL, 0, 0, '2026-05-18 07:20:21', 'Active', NULL, '', 'no', 10, NULL),
(171, 15, 6, 5, 'Colourful', 0, 'Default', 'Elegance abaya', 'عباية الرقي', '', '', 38.00, 38.00, 0.00, 'A royal harmony that combines the depth of black and the luxury of dark blue, for a look that reflects confidence and sophistication.', 'تناغم ملكي يجمع بين عمق اللون الأسود وفخامة اللون الأزرق الداكن، لإطلالة تعكس الثقة والرقي.', '', '', '', NULL, 0, 0, '2026-07-10 18:27:25', 'Active', NULL, '', 'no', 4, NULL),
(172, 15, 6, 5, 'Colourful', 0, 'Default', 'Elegant navy abaya', 'عباية كحلية أنيقة', '', '', 40.00, 40.00, 0.00, 'When black meets the serenity of navy, a work of art is born, granting you a striking presence and a unique signature.', 'عندما يلتقي اللون الأسود بهدوء اللون الكحلي، تولد تحفة فنية، تمنحك حضوراً لافتاً وبصمة فريدة.', '', '', '', NULL, 0, 0, '2026-07-12 10:16:11', 'Active', NULL, '', 'no', 2, NULL),
(173, 15, 6, 6, 'Blazer', 0, 'Default', 'Full lace blazer', 'بليزر دانتيل كامل', '', '', 45.00, 45.00, 0.00, 'Blazer abayas combine the elegance of a formal cut with the delicacy of luxurious lace, giving you a modern and eye-catching look.', 'عبايات بليزر تجمع بين هيبة القصّة الرسمية ورقة الدانتيل الفاخر، لتمنحكِ إطلالة عصرية تخطف الأنظار', '', '', '', NULL, 0, 0, '2026-07-11 17:55:38', 'Active', NULL, '', 'no', 4, NULL),
(174, 15, 6, 6, 'Blazer', 0, 'Default', 'Blazer Abaya', 'عباية بليزر', '', '', 40.00, 40.00, 0.00, 'Powerful presence meets delicate lace; discover blazer abayas with designs that redefine modern elegance.', 'قوة الحضور تلتقي برقة الدانتيل؛ اكتشفي عبايات البليزر بتصاميم تُعيد تعريف الأناقة العصرية', '', '', '', NULL, 0, 0, '2026-07-12 10:38:38', 'Active', NULL, '', 'no', 4, NULL),
(175, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Black abaya  with lace', 'عباية سوداء مزينة بالدانتيل', '', '', 38.00, 38.00, 0.00, 'Beauty lies in simplicity... A soft abaya that gives you freedom of movement without compromising your elegance.', 'الجمال في البساطة.. عباية ناعمة تمنحكِ حرية الحركة دون التنازل عن أناقتكِ.', '', '', '', NULL, 0, 0, '2026-07-12 12:57:36', 'Active', NULL, '', 'no', 2, NULL),
(176, 15, 6, 10, 'Eid Collection', 0, 'Default', 'black blazer with beads', 'بليزر أسود مزين بالخرز', '', '', 40.00, 40.00, 0.00, 'Shiny beads and intricate embroidery give the abaya an elegant presence.', 'خرز لامع تطريز متقن يمنح العباية حضورًا أنيقًا.', '', '', '', NULL, 0, 0, '2026-06-03 04:23:58', 'Active', NULL, '', 'no', 1, NULL),
(177, 15, 6, 10, 'Eid Collection', 0, 'Default', 'luxurious abaya', 'عباية فاخرة', '', '', 40.00, 40.00, 0.00, 'A luxurious abaya made just for you... combining a dignified presence with comfort of movement all day long', 'عباية فاخرة صُنعت لأجلكِ.. تجمع بين هيبة الحضور وراحة التحرك طوال اليوم', '', '', '', NULL, 0, 0, '2026-06-19 06:43:14', 'Active', NULL, '', 'no', 5, NULL),
(178, 15, 6, 10, 'Eid Collection', 0, 'Default', 'luxurious abaya', 'عباية فاخرة', '', '', 38.00, 38.00, 0.00, 'A work of art that reflects your elegance... A luxurious abaya specially crafted to make you the star of every occasion.', 'قطعة فنية تحاكي رقيّكِ.. عباية فاخرة صُنعت خصيصاً لتكوني نجمة كل مناسبة', '', '', '', NULL, 0, 0, '2026-05-17 14:51:24', 'Active', NULL, '', 'no', 2, NULL),
(179, 15, 6, 5, 'Colourful', 0, 'Default', 'Elegance abaya', 'عباية الأناقة', '', '', 40.00, 40.00, 0.00, 'A masterpiece of elegance! This luxurious abaya blends the allure of black with the delicate touch of white, adorned with elegant beading that adds a captivating sparkle to your look. Designed to be your first choice when you seek distinction and uniqueness.', 'لوحة فنية من الأناقة! عباية فاخرة تمزج بين جاذبية الأسود ورقة الأبيض، تزدان بلمسات من الشك الأنيق الذي يضفي بريقاً ساحراً على إطلالتكِ. صُممت لتكون خياركِ الأول عندما تبحثين عن التميز والفرادة.', '', '', '', NULL, 0, 0, '2026-07-12 05:25:19', 'Active', NULL, '', 'no', 2, NULL),
(180, 15, 6, 6, 'Blazer', 0, 'Default', 'Blazer Abaya', 'عباية بليزر', '', '', 40.00, 40.00, 0.00, 'The blazer\\\'s design harmonizes with the delicate lace, creating a look full of confidence and femininity.', 'حيث تتناغم قصة البليزر مع عذوبة الدانتيل، لترسم لكِ إطلالة مفعمة بالثقة والأنوثة', '', '', '', NULL, 0, 0, '2026-07-11 05:29:24', 'Active', NULL, '', 'no', 4, NULL),
(181, 15, 6, 6, 'Blazer', 0, 'Default', 'Blazer Abaya', 'عباية بليزر', '', '', 38.00, 38.00, 0.00, 'This blazer abaya combines the elegance of a formal cut with the delicacy of luxurious lace, giving you a modern and eye-catching look.', 'تجمع هذه العباءة البليزر بين أناقة التصميم الرسمي ورقة الدانتيل الفاخر، مما يمنحكِ إطلالة عصرية وجذابة.', '', '', '', NULL, 0, 0, '2026-07-04 13:52:03', 'Active', NULL, '', 'no', 2, NULL),
(182, 15, 6, 10, 'Eid Collection', 0, 'Default', 'Abaya', 'عباية', '', '', 38.00, 38.00, 0.00, 'For the woman who accepts nothing less than the best, an abaya that reflects luxury in its most splendid form.', 'للمرأة التي لا تقبل بأقل من الأفضل، عباءة تعكس الفخامة بأبهى صورها.', '', '', '', NULL, 0, 0, '2026-06-11 07:22:41', 'Active', NULL, '', 'no', 3, NULL),
(183, 15, 6, 5, 'Colourful', 0, 'Default', 'luxurious abaya', 'عباية فاخرة', '', '', 45.00, 45.00, 0.00, 'For every woman seeking a fresh and distinctive look for her everyday style, we present this unique abaya that combines several harmonious colors to give you a wide and radiant appearance. It has been meticulously designed to blend modern elegance with exceptional comfort, where the colors flow seamlessly to suit all your occasions and add a touch of vibrancy to your presence. Be among the first to shine with a style that combines simplicity and innovation.', 'لكل امرأة تبحث عن إطلالة جديدة ومميزة لإطلالتها اليومية، نقدم هذه العباية الفريدة التي تجمع بين عدة ألوان متناسقة لتمنحكِ مظهراً واسعاً ومشرقاً. صُممت بعناية فائقة لتجمع بين الأناقة العصرية والراحة الاستثنائية، حيث تنساب الألوان بسلاسة لتناسب جميع مناسباتكِ وتضفي لمسة من الحيوية على حضوركِ. كوني من أوائل المتألقات بأسلوب يجمع بين البساطة والابتكار.', '', '', '', NULL, 0, 0, '2026-07-04 12:20:53', 'Active', NULL, '', 'no', 1, NULL),
(184, 15, 6, 5, 'Colourful', 0, 'Default', 'STYLISH ABAYA', 'عباية أنيقة', '', '', 45.00, 45.00, 0.00, 'A work of art that combines luxury and bold design. This abaya features a carefully crafted blend of several luxurious colors, chosen to reflect your refined taste. High-quality fabric and an impeccable cut highlight the beauty of the multi-colored pieces without being overly extravagant, making it the perfect choice for a striking and sophisticated look at your gatherings and special occasions. An abaya designed to give you an unforgettable presence.', 'تحفة فنية تجمع بين الفخامة والتصميم الجريء. تتميز هذه العباية بمزيج متقن من ألوان فاخرة مختارة بعناية لتعكس ذوقك الرفيع. قماش عالي الجودة وقصة متقنة تبرز جمال الألوان المتعددة دون مبالغة، مما يجعلها الخيار الأمثل لإطلالة أنيقة وجذابة في مناسباتك الخاصة. عباية مصممة لتمنحك حضورًا لا يُنسى.', '', '', '', NULL, 0, 0, '2026-07-12 03:44:15', 'Active', NULL, '', 'no', 2, NULL),
(185, 15, 6, 5, 'Colourful', 0, 'Default', 'luxurious maroon abaya', 'عباية مارونية فاخرة', '', '', 40.00, 40.00, 0.00, 'A luxurious maroon abaya adorned with sequins and full lace on the back  for a look that exudes elegance and sophistication.', 'عباية مارونية فاخرة مزينة بالشك ومن الخلف ظهر دانتيل كامل لإطلالة تنبض بالأناقة والرقي.', '', '', '', NULL, 0, 0, '2026-07-11 16:59:25', 'Active', NULL, '', 'no', 2, NULL),
(186, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Black Abaya', 'عباية سوداء', '', '', 38.00, 38.00, 0.00, 'An elegant abaya with full lace back and a sophisticated design and details that exude a great sense of luxury and tranquility everywhere.', 'عباءة أنيقة ذات ظهر من الدانتيل بالكامل وتصميم وتفاصيل راقية تنضح بإحساس كبير بالفخامة والهدوء في كل مكان.', '', '', '', NULL, 0, 0, '2026-07-12 18:34:05', 'Active', NULL, '', 'no', 2, NULL),
(187, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Black Abaya', 'عباية سوداء', '', '', 38.00, 38.00, 0.00, 'A luxurious black abaya with elegant feminine touches that suits your everyday looks and special occasions with complete style.', 'عباية سوداء فاخرة بلمسات أنثوية أنيقة تناسب إطلالاتك اليومية والمناسبات الخاصة بكل أناقة.', '', '', '', NULL, 0, 0, '2026-07-10 20:07:58', 'Active', NULL, '', 'no', 2, NULL),
(188, 15, 6, 10, 'Eid Collection', 0, 'Default', 'luxurious abaya', 'عباية فاخرة', '', '', 45.00, 45.00, 0.00, 'A piece designed to give you an elegant presence and confidence that suits every detail of you.', 'قطعة صُممت لتمنحك حضورًا أنيقًا وثقة تليق بكل تفاصيلك.', '', '', '', NULL, 0, 0, '2026-05-20 11:59:43', 'Active', NULL, '', 'no', 2, NULL),
(189, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Black Abaya', 'عباية سوداء', '', '', 38.00, 38.00, 0.00, 'A black abaya with a modern style gives you an elegant look that expresses your style with utmost grace.', 'العباية السوداء ذات الطراز العصري تمنحك إطلالة أنيقة تعبر عن أسلوبك بأقصى درجات الرقي.', '', '', '', NULL, 0, 0, '2026-07-01 14:26:55', 'Active', NULL, '', 'no', 3, NULL),
