(194, 15, 6, 6, 'Blazer', 0, 'Default', 'Blazer Abaya', 'عباية بليزر', '', '', 40.00, 40.00, 0.00, 'A luxurious brown blazer abaya, designed from two pieces of interlocking jacquard fabric. It combines the elegance of a blazer with the practicality of an abaya, making it the perfect piece for a formal yet comfortable look.', 'عباية بليزر بلون بني فاخر، مصممة من قطعتين من قماش الجاكار المتداخل. تجمع بين أناقة البليزر وعملية العباية، مما يجعلها قطعة مثالية لإطلالة رسمية ومريحة في آن واحد.', '', '', '', NULL, 0, 0, '2026-07-01 03:27:07', 'Active', NULL, '', 'no', 2, NULL),
(195, 15, 6, 5, 'Colourful', 0, 'Default', 'Abaya', 'عباية', '', '', 38.00, 38.00, 0.00, 'This mixed-color abaya is crafted from soft, flowing fabric for exceptional ease of movement. Its design combines harmonious colors with a modern cut, making it an ideal choice for a sophisticated yet comfortable look.', 'عباية ميكس ألوان، مصممة من قماش التكتوك الناعم لتمنحكِ انسيابية فائقة في الحركة. تصميم يجمع بين دمج الألوان المتناغم والقصة العصرية، مما يجعلها خياراً مثالياً لإطلالة راقية ومريحة في آن واحد.', '', '', '', NULL, 0, 0, '2026-07-04 21:52:20', 'Active', NULL, '', 'no', 9, NULL),
(196, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Simple Black Abaya', 'عباية سوداء بسيطة', '', '', 35.00, 35.00, 0.00, 'An abaya carefully designed to highlight the beauty of the look in an elegant style that suits your distinctive taste.', 'عباية مصممة بعناية لتبرز جمال الإطلالة بأسلوب راقٍ يليق بذوقك المميز.', '', '', '', NULL, 0, 0, '2026-07-15 18:19:35', 'Active', NULL, '', 'no', 3, NULL),
(197, 15, 6, 4, 'Black Abaya', 0, 'Default', 'Abaya', 'عباية', '', '', 38.00, 38.00, 0.00, 'Black elegance embodied in a luxurious design and details that give you a distinct presence in a simple way.', 'أناقة سوداء متجسدة في تصميم فاخر وتفاصيل تمنحك حضوراً مميزاً بطريقة بسيطة.', '', '', '', NULL, 0, 0, '2026-06-30 19:51:36', 'Active', NULL, '', 'no', 4, NULL),
